1771 Instruction *InstCombinerImpl::foldOpIntoPhi(Instruction &I, PHINode *PN) {
1772   unsigned NumPHIValues = PN->getNumIncomingValues();
1773   if (NumPHIValues == 0)
1774     return nullptr;
1775 
1776   // We normally only transform phis with a single use.  However, if a PHI has
1777   // multiple uses and they are all the same operation, we can fold *all* of the
1778   // uses into the PHI.
1779   if (!PN->hasOneUse()) {
1780     // Walk the use list for the instruction, comparing them to I.
1781     for (User *U : PN->users()) {
1782       Instruction *UI = cast<Instruction>(U);
1783       if (UI != &I && !I.isIdenticalTo(UI))
1784         return nullptr;
1785     }
1786     // Otherwise, we can replace *all* users with the new PHI we form.
1787   }
1788 
1789   // Check that all operands are phi-translatable.
1790   for (Value *Op : I.operands()) {
1791     if (Op == PN)
1792       continue;
1793 
1794     // Non-instructions never require phi-translation.
1795     auto *I = dyn_cast<Instruction>(Op);
1796     if (!I)
1797       continue;
1798 
1799     // Phi-translate can handle phi nodes in the same block.
1800     if (isa<PHINode>(I))
1801       if (I->getParent() == PN->getParent())
1802         continue;
1803 
1804     // Operand dominates the block, no phi-translation necessary.
1805     if (DT.dominates(I, PN->getParent()))
1806       continue;
1807 
1808     // Not phi-translatable, bail out.
1809     return nullptr;
1810   }
1811 
1812   // Check to see whether the instruction can be folded into each phi operand.
1813   // If there is one operand that does not fold, remember the BB it is in.
1814   SmallVector<Value *> NewPhiValues;
1815   SmallVector<unsigned int> OpsToMoveUseToIncomingBB;
1816   bool SeenNonSimplifiedInVal = false;
1817   for (unsigned i = 0; i != NumPHIValues; ++i) {
1818     Value *InVal = PN->getIncomingValue(i);
1819     BasicBlock *InBB = PN->getIncomingBlock(i);
1820 
1821     if (auto *NewVal = simplifyInstructionWithPHI(I, PN, InVal, InBB, DL, SQ)) {
1822       NewPhiValues.push_back(NewVal);
1823       continue;
1824     }
1825 
1826     // If the only use of phi is comparing it with a constant then we can
1827     // put this comparison in the incoming BB directly after a ucmp/scmp call
1828     // because we know that it will simplify to a single icmp.
1829     const APInt *Ignored;
1830     if (isa<CmpIntrinsic>(InVal) && InVal->hasOneUser() &&
1831         match(&I, m_ICmp(m_Specific(PN), m_APInt(Ignored)))) {
1832       OpsToMoveUseToIncomingBB.push_back(i);
1833       NewPhiValues.push_back(nullptr);
1834       continue;
1835     }
1836 
1837     if (SeenNonSimplifiedInVal)
1838       return nullptr; // More than one non-simplified value.
1839     SeenNonSimplifiedInVal = true;
1840 
1841     // If there is exactly one non-simplified value, we can insert a copy of the
1842     // operation in that block.  However, if this is a critical edge, we would
1843     // be inserting the computation on some other paths (e.g. inside a loop).
1844     // Only do this if the pred block is unconditionally branching into the phi
1845     // block. Also, make sure that the pred block is not dead code.
1846     BranchInst *BI = dyn_cast<BranchInst>(InBB->getTerminator());
1847     if (!BI || !BI->isUnconditional() || !DT.isReachableFromEntry(InBB))
1848       return nullptr;
1849 
1850     NewPhiValues.push_back(nullptr);
1851     OpsToMoveUseToIncomingBB.push_back(i);
1852 
1853     // If the InVal is an invoke at the end of the pred block, then we can't
1854     // insert a computation after it without breaking the edge.
1855     if (isa<InvokeInst>(InVal))
1856       if (cast<Instruction>(InVal)->getParent() == InBB)
1857         return nullptr;
1858 
1859     // Do not push the operation across a loop backedge. This could result in
1860     // an infinite combine loop, and is generally non-profitable (especially
1861     // if the operation was originally outside the loop).
1862     if (isBackEdge(InBB, PN->getParent()))
1863       return nullptr;
1864   }
1865 
1866   // Clone the instruction that uses the phi node and move it into the incoming
1867   // BB because we know that the next iteration of InstCombine will simplify it.
1868   SmallDenseMap<BasicBlock *, Instruction *> Clones;
1869   for (auto OpIndex : OpsToMoveUseToIncomingBB) {
1870     Value *Op = PN->getIncomingValue(OpIndex);
1871     BasicBlock *OpBB = PN->getIncomingBlock(OpIndex);
1872 
1873     Instruction *Clone = Clones.lookup(OpBB);
1874     if (!Clone) {
1875       Clone = I.clone();
1876       for (Use &U : Clone->operands()) {
1877         if (U == PN)
1878           U = Op;
1879         else
1880           U = U->DoPHITranslation(PN->getParent(), OpBB);
1881       }
1882       Clone = InsertNewInstBefore(Clone, OpBB->getTerminator()->getIterator());
1883       Clones.insert({OpBB, Clone});
1884     }
1885 
1886     NewPhiValues[OpIndex] = Clone;
1887   }
1888 
1889   // Okay, we can do the transformation: create the new PHI node.
1890   PHINode *NewPN = PHINode::Create(I.getType(), PN->getNumIncomingValues());
1891   InsertNewInstBefore(NewPN, PN->getIterator());
1892   NewPN->takeName(PN);
1893   NewPN->setDebugLoc(PN->getDebugLoc());
1894 
1895   for (unsigned i = 0; i != NumPHIValues; ++i)
1896     NewPN->addIncoming(NewPhiValues[i], PN->getIncomingBlock(i));
1897 
1898   for (User *U : make_early_inc_range(PN->users())) {
1899     Instruction *User = cast<Instruction>(U);
1900     if (User == &I)
1901       continue;
1902     replaceInstUsesWith(*User, NewPN);
1903     eraseInstFromFunction(*User);
1904   }
1905 
1906   replaceAllDbgUsesWith(const_cast<PHINode &>(*PN),
1907                         const_cast<PHINode &>(*NewPN),
1908                         const_cast<PHINode &>(*PN), DT);
1909   return replaceInstUsesWith(I, NewPN);
1910 }
