1912 Instruction *InstCombinerImpl::foldBinopWithPhiOperands(BinaryOperator &BO) {
1913   // TODO: This should be similar to the incoming values check in foldOpIntoPhi:
1914   //       we are guarding against replicating the binop in >1 predecessor.
1915   //       This could miss matching a phi with 2 constant incoming values.
1916   auto *Phi0 = dyn_cast<PHINode>(BO.getOperand(0));
1917   auto *Phi1 = dyn_cast<PHINode>(BO.getOperand(1));
1918   if (!Phi0 || !Phi1 || !Phi0->hasOneUse() || !Phi1->hasOneUse() ||
1919       Phi0->getNumOperands() != Phi1->getNumOperands())
1920     return nullptr;
1921 
1922   // TODO: Remove the restriction for binop being in the same block as the phis.
1923   if (BO.getParent() != Phi0->getParent() ||
1924       BO.getParent() != Phi1->getParent())
1925     return nullptr;
